 1	import React, { FC } from 'react';
 2	
 3	import { V1beta1DataSource } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 4	import {
 5	  ConditionsTable,
 6	  K8sResourceCondition,
 7	} from '@kubevirt-utils/components/ConditionsTable/ConditionsTable';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { Divider, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
10	
11	import { DataSourceDetailsGrid } from './components/DataSourceDetailsGrid.tsx/DataSourceDetailsGrid';
12	
13	type DataSourceDetailsPageProps = {
14	  obj?: V1beta1DataSource;
15	};
16	
17	const DataSourceDetailsPage: FC<DataSourceDetailsPageProps> = ({ obj: dataSource }) => {
18	  const { t } = useKubevirtTranslation();
19	
20	  return (
21	    <div>
22	      <PageSection variant={PageSectionVariants.light}>
23	        <Title className="co-section-heading" headingLevel="h2">
24	          {t('DataSource details')}
25	        </Title>
26	        <DataSourceDetailsGrid dataSource={dataSource} />
27	      </PageSection>
28	      <Divider />
29	      <PageSection variant={PageSectionVariants.light}>
30	        <Title className="co-section-heading" headingLevel="h2">
31	          {t('Conditions')}
32	        </Title>
33	        <ConditionsTable conditions={dataSource?.status?.conditions as K8sResourceCondition[]} />
34	      </PageSection>
35	    </div>
36	  );
37	};
38	
39	export default DataSourceDetailsPage;

